I noted that Datatable's [`pageLength`](https://datatables.net/reference/option/pageLength) option is ignored when specified in javascript initialization. This is the init code.

```
$(document).ready(function() {
    datatableview.auto_initialize = false;
    datatableview.initialize($('.datatable'), {
        'pageLength': 10 // Ignored, always shows 25 results
    });
});
```
Even if pageLength is `10` it always shows 25 results, and the generated markup reflects this as well:
```
<table data-page-length="25"  role="grid" aria-describedby="DataTables_Table_0_info">
...
</table>
```

It works if I configure the page length via configuration object in Python, but I wonder if this is the expected behavior or if I'm doing something wrong.
```
class MyDataTable(Datatable):
    class Meta:
        model = Article
        page_length = 10 // Works
```

For some methods (e.g. `pause()`), there are common causes of failure (e.g. nothing to pause) which result in specific error codes (e.g. UPnP Error 701).
We should collect those error codes and document them together with their meaning in the docstring of each method.

Previous conversation about this topic on #454:

@KennethNielsen [commented on 18 Jan 2017](https://github.com/SoCo/SoCo/issues/454#issuecomment-273420182) on #454:
> I can see in the source code that it is documented that e.g. play and pause may raise SoCoUPnPException, but it does not mention anything about the error code. It may be useful to add a little something to the docstrings about the most common sources of failures and about more acceptable sources of failures, such as this one. What do you think.

@ghcs27 [commented on 18 Jan 2017](https://github.com/SoCo/SoCo/issues/454#issuecomment-273514884) on #454:
> I would support adding UPnP error codes and their meaning to the docs. The basic meaning of the error codes can be found on page 89 of the UPnP specs, but some codes probably have a Sonos specific meaning.

@KennethNielsen [commented on 21 Jan 2017[(https://github.com/SoCo/SoCo/issues/454#issuecomment-274274520) on #454:
It might be that we should add some sort of list (probably not exhaustive though, but with links) somewhere in the docs, but my question was more whether it would be a good idea to explain one or 2 particularly relevant error codes in the doc string for methods like e.g. pause. Thoughts?

I implemented this in a fork of this repo. Not sure if this is the best way but it's working for me.

```
var async = require('async');
var plugins = require('./exports.js');
var collector = require('./collect.js');
var commandLineArgs = require('command-line-args');
var csvWriter = require('csv-write-stream');
var fs = require('fs');

//define the command-line args we will support
const optionDefinitions = [
  { name: 'export', type: String }
]
//parse the command-line args - available in options
const options = commandLineArgs(optionDefinitions)

var exportCSV = false;
if (options.export) {
    if (options.export.toLowerCase() === 'csv') {
        exportCSV = true;
    }
}

var AWSConfig;

// OPTION 1: Configure AWS credentials through hard-coded key and secret
// AWSConfig = {
//     accessKeyId: '',
//     secretAccessKey: '',
//     sessionToken: '',
//     region: 'us-east-1'
// };

AWSConfig = require(__dirname + '/credentials.json');

// OPTION 3: ENV configuration with AWS_ env vars
if(process.env.AWS_ACCESS_KEY_ID && process.env.AWS_SECRET_ACCESS_KEY){
    AWSConfig = {
        accessKeyId: process.env.AWS_ACCESS_KEY_ID,
        secretAccessKey:  process.env.AWS_SECRET_ACCESS_KEY,
        sessionToken: process.env.AWS_SESSION_TOKEN,
        region: process.env.AWS_DEFAULT_REGION || 'us-east-1'
    };
}

if (!AWSConfig || !AWSConfig.accessKeyId) {
    return console.log('ERROR: Invalid AWSConfig');
}

var skipRegions = [];   // Add any regions you wish to skip here. Ex: 'us-east-2'

// Custom settings - place plugin-specific settings here
var settings = {};

// STEP 1 - Obtain API calls to make
console.log('INFO: Determining API calls to make...');

var apiCalls = [];

for (p in plugins) {
    for (a in plugins[p].apis) {
        if (apiCalls.indexOf(plugins[p].apis[a]) === -1) {
            apiCalls.push(plugins[p].apis[a]);
        }
    }
}

console.log('INFO: API calls determined.');
console.log('INFO: Collecting AWS metadata. This may take several minutes...');

// STEP 2 - Collect API Metadata from AWS
collector(AWSConfig, {api_calls: apiCalls, skip_regions: skipRegions}, function(err, collection){
    if (err || !collection) return console.log('ERROR: Unable to obtain API metadata');

    console.log('INFO: Metadata collection complete. Analyzing...');
    console.log('INFO: Analysis complete. Scan report to follow...\n');

    if (exportCSV) {
        var writer = csvWriter({headers: ["category", "title", "resource", "region", "statusWord", "message"]});
        writer.pipe(fs.createWriteStream('results.csv'));
    }

    async.forEachOfLimit(plugins, 10, function(plugin, key, callback){
        plugin.run(collection, settings, function(err, results){
            for (r in results) {
                var statusWord;
                if (results[r].status === 0) {
                    statusWord = 'OK';
                } else if (results[r].status === 1) {
                    statusWord = 'WARN';
                } else if (results[r].status === 2) {
                    statusWord = 'FAIL';
                } else {
                    statusWord = 'UNKNOWN';
                }

                console.log(plugin.category + '\t' + plugin.title + '\t' +
                            (results[r].resource || 'N/A') + '\t' +
                            (results[r].region || 'Global') + '\t\t' +
                            statusWord + '\t' + results[r].message);


		//if the user asks us to export to csv lets do that
		if (exportCSV) {
		    writer.write([plugin.category, plugin.title, (results[r].resource || 'N/A'), (results[r].region || 'Global'), statusWord, results[r].message])
		}
            }

            callback(err);
        });
    }, function(err){
        if (err) return console.log(err);
    });

    if (exportCSV) {
        writer.end();
        console.log('INFO: Results available at results.csv.');
    }
});
```

