Call to super().__init__ of ObjectType resets all previously set field attributes to None.

This behavior was introduced by fix of issue #585.


```python

from graphene import ObjectType, String, Field, Schema


def test_objecttype_reset_attribute():
    class User(ObjectType):
        name = String(required=True)

        def __init__(self, *args, **kwargs):
            self.name = 'Default Name'
            super().__init__(*args, **kwargs)

    class Query(ObjectType):
        user = Field(User)

        def resolve_user(self, info):
            return User()

    schema = Schema(query=Query)
    result = schema.execute(''' query basequery {
        user {
            name
        }
    }
    ''')
    assert not result.errors
    assert result.data == {
        'user': {
            'name': 'Default Name',
        }
    }
```

